 104→                // if (i_ker_x >= in_tensor_dim)
 105→                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
 106→                {
 107→                    pBuffer += 3;
 108→                }
 109→            }
