1027→                                conv_out +=
1028→                                    in_tensor[(in_row * in_tensor_dim + in_col) * 3 + l]
1029→                                    * ker_weight[i * 3 * ker_dim * ker_dim + (m * ker_dim + n) * 3 + l];
1030→                            }
1031→                        }
1032→                    }
1033→                }
1034→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1035→                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
1036→            }
1037→        }
1038→    }
1039→#endif
1040→
1041→    return 0;
1042→}
