            while(colCnt2 > 0)
            {
                NDS_VEC_VSETVLI_E16(vl, colCnt2);
                NDS_VEC_VLB_V(NDS_VEC_V0, pA);
                NDS_VEC_VLB_V(NDS_VEC_V1, pB);
                NDS_VEC_VWMACC_VV(NDS_VEC_V2, NDS_VEC_V1, NDS_VEC_V0);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            NDS_VEC_VSETVLI_E32_M2(vl, colCnt);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V4, NDS_VEC_V2, NDS_VEC_V4);
            //move vr results to gpr
            NDS_VEC_VMV_X_S(sum, NDS_VEC_V4);

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> post_rshift), 8);
        }
    }
#endif
#endif
#elif defined(ENA_DSP_ISA_V5)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *wt_tmp = (q7_t*)ker_weight;

    q7_t    *pBuffer = (q7_t *)in_tmp_buf;
    q7_t     *pOut = out_tensor;

    uint32_t i;
    q7_t    *pBufferB = (q7_t *)wt_tmp_buf;

    uint16_t totalsize = 3 * ker_dim * ker_dim;
    for (i = 0; i < out_tensor_ch; i++)
    {
        uint32_t j;
        for (j = 0; j < totalsize; j++)
        {
            *pBufferB++ = *wt_tmp++;
        }
        *pBufferB++ = 0;
    }

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                    }
                    else
                    {
                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                    }
                }
            }
            *pBuffer++ = 0;

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft((q7_t *)wt_tmp_buf, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, pre_rshift, out_scale, post_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

    /* left-over because odd number of output pixels */
#ifdef ENA_DSP_ISA_64
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            long sum = 0;
            q7_t *pB = (q7_t*)in_tmp_buf;

            /* basically each time it process 8 entries */
            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 3;

            while (colCnt)
            {
                long inA1, inB1;
                inA1 = *__SIMD64(pA)++;
                inB1 = *__SIMD64(pB)++;
                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }
            //sum up the high and low part results (SIMD results)
            sum = (q31_t)(sum >> 32) + (q31_t)sum;

            colCnt = 3 * ker_dim * ker_dim & 0x7;
            while (colCnt)
            {
                q7_t inA1 = *pA++;
                q7_t inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            //add bias back
            sum += *bias++;

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#else
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            long sum = *bias++;
            q7_t *pB = (q7_t*)in_tmp_buf;

            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
            while (colCnt)
            {
                long inA1, inB1;
                inA1 = *__SIMD32(pA)++;
                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }

            colCnt = 3 * ker_dim * ker_dim & 0x3;
            while (colCnt)
            {
                q7_t inA1 = *pA++;
                q7_t inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#endif
#elif defined(ENA_DSP_ISA)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *wt_tmp = (q7_t*)ker_weight;
    q15_t *pBuffer = in_tmp_buf;
    q7_t *pOut = out_tensor;

    uint32_t i;
    uint16_t size;
    uint16_t size2 = (3 * ker_dim * ker_dim) >> 2;
    q31_t tmp;
    q31_t *pwt2 = (q31_t *)wt_tmp_buf;
    for (i = 0; i < out_tensor_ch; i++)
