            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
            // {
            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            //     //load src1
            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
            //     //load src2
            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
            //     //bump pointers and update loop counter
            //     colCnt2 -= vl;
            //     p_wt += vl;
            //     p_in += vl;
            //     //set the proper avl/SEW/LMUL values for vd4dot
            //     vl >>= 2;
            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            //     //acc += src1 * src2
            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            // }

            //extra process for the case of elements to be dot producted is not a mutiple of 4
            while(colCnt2 > 0)
            {
                //clean one of the dot product source
                NDS_VEC_VSETVLI(vl, zero, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);

                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                //load src1
                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
                //load src2
                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                p_wt += vl;
                p_in += vl;
                //set the proper avl/SEW/LMUL values for vd4dot
                //remember to deal with the elements to be dot producted is not a multiple of 4 case
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                //acc += src1 * src2
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);

            //add bias back
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLW_V(NDS_VEC_V9, bias);
            NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);

            //2-stage shift
            NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
            NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
            NDS_VEC_VADD_VX(NDS_VEC_V8, NDS_VEC_V8, NN_ROUND(post_rshift));

            //scale down, clip and store the results
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
            NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
            bias += vl;
            pOut += vl;
        }
    }
#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
    /* left-over because odd number of output pixels */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        long i;
        /* basically each time it process 4 entries */
        long colCnt = (3 * ker_dim * ker_dim);

        //set SEW for 1st time VMV_S_X
        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t sum = bias[i];
            q7_t *pB = (q7_t*)in_tmp_buf;
            long colCnt2 = colCnt;

            //init
            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
            //clear v8~v15 (acc)
            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);

            while(colCnt2 > 0)
            {
                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
                NDS_VEC_VQMACC_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V8, NDS_VEC_V0);
            //move vr results to gpr
            NDS_VEC_VMV_X_S(sum, NDS_VEC_V1);

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 8);
        }
    }
#elif (NDS_VEC_RVV_VERSION == 80)
    /* left-over because odd number of output pixels */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;
        /* basically each time it process 4 entries */
        uint16_t colCnt = (3 * ker_dim * ker_dim);

        //set SEW for 1st time VMV_S_X
        //LMUL=2 is just for clear v2~v3 (vmv ignores LMUL)
        NDS_VEC_VSETVLI_E32_M2(vl, colCnt);

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t sum = bias[i];
            q7_t *pB = (q7_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //init
            NDS_VEC_VMV_S_X(NDS_VEC_V4, sum);
            //clear v2~v3 (acc)
            NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0x0);

            while(colCnt2 > 0)
            {
                NDS_VEC_VSETVLI_E16(vl, colCnt2);
                NDS_VEC_VLB_V(NDS_VEC_V0, pA);
                NDS_VEC_VLB_V(NDS_VEC_V1, pB);
                NDS_VEC_VWMACC_VV(NDS_VEC_V2, NDS_VEC_V1, NDS_VEC_V0);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            NDS_VEC_VSETVLI_E32_M2(vl, colCnt);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V4, NDS_VEC_V2, NDS_VEC_V4);
            //move vr results to gpr
            NDS_VEC_VMV_X_S(sum, NDS_VEC_V4);

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = (q7_t) NDS_ISA_SATS((sum >> post_rshift), 8);
        }
    }
#endif
#endif
#elif defined(ENA_DSP_ISA_V5)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *wt_tmp = (q7_t*)ker_weight;

    q7_t    *pBuffer = (q7_t *)in_tmp_buf;
    q7_t     *pOut = out_tensor;

    uint32_t i;
    q7_t    *pBufferB = (q7_t *)wt_tmp_buf;

    uint16_t totalsize = 3 * ker_dim * ker_dim;
    for (i = 0; i < out_tensor_ch; i++)
    {
        uint32_t j;
        for (j = 0; j < totalsize; j++)
        {
            *pBufferB++ = *wt_tmp++;
        }
        *pBufferB++ = 0;
    }

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                    }
                    else
                    {
                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                    }
                }
            }
            *pBuffer++ = 0;

            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft((q7_t *)wt_tmp_buf, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, pre_rshift, out_scale, post_rshift, bias, pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

    /* left-over because odd number of output pixels */
#ifdef ENA_DSP_ISA_64
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            long sum = 0;
            q7_t *pB = (q7_t*)in_tmp_buf;

            /* basically each time it process 8 entries */
            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 3;

            while (colCnt)
            {
                long inA1, inB1;
                inA1 = *__SIMD64(pA)++;
                inB1 = *__SIMD64(pB)++;
                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }
            //sum up the high and low part results (SIMD results)
            sum = (q31_t)(sum >> 32) + (q31_t)sum;

            colCnt = 3 * ker_dim * ker_dim & 0x7;
            while (colCnt)
            {
                q7_t inA1 = *pA++;
                q7_t inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            //add bias back
            sum += *bias++;

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#else
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            long sum = *bias++;
            q7_t *pB = (q7_t*)in_tmp_buf;

            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
            while (colCnt)
            {
                long inA1, inB1;
                inA1 = *__SIMD32(pA)++;
                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }

            colCnt = 3 * ker_dim * ker_dim & 0x3;
            while (colCnt)
            {
                q7_t inA1 = *pA++;
                q7_t inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#endif
#elif defined(ENA_DSP_ISA)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    q7_t *wt_tmp = (q7_t*)ker_weight;
    q15_t *pBuffer = in_tmp_buf;
    q7_t *pOut = out_tensor;

    uint32_t i;
    uint16_t size;
    uint16_t size2 = (3 * ker_dim * ker_dim) >> 2;
    q31_t tmp;
    q31_t *pwt2 = (q31_t *)wt_tmp_buf;
    for (i = 0; i < out_tensor_ch; i++)
    {
        size = size2;
        while (size != 0)
        {
            tmp = *__SIMD32(wt_tmp)++;;
            *pwt2++ = NDS_DSP_SUNPKD810(tmp);
            *pwt2++ = NDS_DSP_SUNPKD810(tmp >> 16);
            size--;
        }
        q7_t tmp1 = *wt_tmp++;
        q7_t tmp2 = *wt_tmp++;
        *pwt2++ = NDS_DSP_PKBB16(tmp2, tmp1);
        tmp1 = *wt_tmp++;
        *pwt2++ = (u16_t)tmp1;
    }

    // This part implements the im2col function
    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
                    {
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                        *pBuffer++ = 0;
                    }
                    else
                    {
                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                        *pBuffer++ = *pPixel++;
                    }
                }
            }
            *pBuffer++ = 0;

            if (pBuffer == in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
            {
                pOut = nn_mat_mul_kernel_q15_q15_q7_bias_2sft(wt_tmp_buf, in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, pre_rshift, out_scale, post_rshift, bias, pOut);
                pBuffer = in_tmp_buf;
            }
        }
    }

    if (pBuffer != in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int i;

        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t   sum = bias[i];
            q15_t   *pB = in_tmp_buf;

            /* basically each time it process 4 entries */
            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;

            while (colCnt)
            {
                q31_t     inA1, inA2;
                q31_t     inB1, inB2;

                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA1, inB1);
                inB2 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA2, inB2);

                colCnt--;
            }
            colCnt = 3 * ker_dim * ker_dim & 0x3;
            while (colCnt)
            {
                q7_t      inA1 = *pA++;
                q15_t     inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#else
    uint16_t  i, j, k, l, m, n;
    int       conv_out;
    long in_row, in_col;

    for (i = 0; i < out_tensor_ch; i++)
    {
        for (j = 0; j < out_tensor_dim; j++)
        {
            for (k = 0; k < out_tensor_dim; k++)
            {
                conv_out = bias[i];
                for (m = 0; m < ker_dim; m++)
                {
                    for (n = 0; n < ker_dim; n++)
                    {
                        /* if-for implementation */
                        in_row = stride * j + m - pad;
                        in_col = stride * k + n - pad;
                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
                        {
                            for (l = 0; l < 3; l++)
                            {
                                conv_out +=
                                    in_tensor[(in_row * in_tensor_dim + in_col) * 3 + l]
                                    * ker_weight[i * 3 * ker_dim * ker_dim + (m * ker_dim + n) * 3 + l];
                            }
                        }
                    }
                }
                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
            }
        }
    }
#endif

    return 0;
}

