1336→        vint32m2_t vAcc4 = __riscv_vundefined_i32m2();
1337→        vint32m2_t vAcc5 = __riscv_vundefined_i32m2();
1338→        vint32m2_t vAcc6 = __riscv_vundefined_i32m2();
1339→        vint32m2_t vAcc7 = __riscv_vundefined_i32m2();
1340→        // setup pointers for two sources
1341→        const q7_t *pB = src2;
1342→        const q7_t *pB2 = pB + col_src1;
1343→        const q7_t *pA2 = src1 + col_src1;
1344→        const q7_t *pA3 = pA2 + col_src1;
1345→        const q7_t *pA4 = pA3 + col_src1;
1346→
1347→        //clear v0~v15 (keep multiplication results)
1348→        vAcc0 = __riscv_vand_tu(vAcc0, vAcc0, zero, vl);
1349→        vAcc1 = __riscv_vand_tu(vAcc1, vAcc1, zero, vl);
1350→        vAcc2 = __riscv_vand_tu(vAcc2, vAcc2, zero, vl);
1351→        vAcc3 = __riscv_vand_tu(vAcc3, vAcc3, zero, vl);
1352→        vAcc4 = __riscv_vand_tu(vAcc4, vAcc4, zero, vl);
1353→        vAcc5 = __riscv_vand_tu(vAcc5, vAcc5, zero, vl);
1354→        vAcc6 = __riscv_vand_tu(vAcc6, vAcc6, zero, vl);
1355→        vAcc7 = __riscv_vand_tu(vAcc7, vAcc7, zero, vl);
1356→
1357→        unsigned long colCnt = col_src1;
1358→        while(colCnt >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M2))
1359→        {
1360→            vl = __riscv_vsetvl_e8m2(colCnt);
1361→            //load src1
1362→            vint8m2_t vSrc1_i8 = __riscv_vle8_v_i8m2(src1, vl);
1363→            vint8m2_t vPa2_i8 = __riscv_vle8_v_i8m2(pA2, vl);
1364→            vint8m2_t vPa3_i8 = __riscv_vle8_v_i8m2(pA3, vl);
1365→            vint8m2_t vPa4_i8 = __riscv_vle8_v_i8m2(pA4, vl);
1366→            //load src2
1367→            vint8m2_t vPb_i8 = __riscv_vle8_v_i8m2(pB, vl);
1368→            vint8m2_t vPb2_i8 = __riscv_vle8_v_i8m2(pB2, vl);
1369→
1370→            //bump pointers and update loop counter
1371→            colCnt -= vl;
1372→            src1 += vl;
1373→            pA2 += vl;
1374→            pA3 += vl;
1375→            pA4 += vl;
1376→            pB += vl;
1377→            pB2 += vl;
1378→
1379→            //set the proper avl/SEW/LMUL values for vd4dot
1380→            vl >>= 2;
1381→            vl = __riscv_vsetvl_e32m2(vl);
1382→
1383→            //acc += src1 * src2
1384→            vAcc0 = __riscv_vd4dots_vv_i32m2(vAcc0, vSrc1_i8, vPb_i8, vl);
1385→            vAcc1 = __riscv_vd4dots_vv_i32m2(vAcc1, vSrc1_i8, vPb2_i8, vl);
1386→            vAcc2 = __riscv_vd4dots_vv_i32m2(vAcc2, vPa2_i8, vPb_i8, vl);
1387→            vAcc3 = __riscv_vd4dots_vv_i32m2(vAcc3, vPa2_i8, vPb2_i8, vl);
1388→            vAcc4 = __riscv_vd4dots_vv_i32m2(vAcc4, vPa3_i8, vPb_i8, vl);
1389→            vAcc5 = __riscv_vd4dots_vv_i32m2(vAcc5, vPa3_i8, vPb2_i8, vl);
1390→            vAcc6 = __riscv_vd4dots_vv_i32m2(vAcc6, vPa4_i8, vPb_i8, vl);
1391→            vAcc7 = __riscv_vd4dots_vv_i32m2(vAcc7, vPa4_i8, vPb2_i8, vl);
1392→        }
1393→
1394→        //extra process for the case of elements to be dot producted is not a mutiple of 4
1395→        if(colCnt > 0)
1396→        {
1397→            //clean one of the dot product source
1398→            vl = __riscv_vsetvlmax_e8m2();
1399→            vint8m2_t vSrc1_i8 = __riscv_vundefined_i8m2();
1400→            vint8m2_t vPa2_i8 = __riscv_vundefined_i8m2();
1401→            vint8m2_t vPa3_i8 = __riscv_vundefined_i8m2();
1402→            vint8m2_t vPa4_i8 = __riscv_vundefined_i8m2();
1403→            vint8m2_t vPb_i8 = __riscv_vundefined_i8m2();
1404→            vint8m2_t vPb2_i8 = __riscv_vundefined_i8m2();
1405→			vPb_i8 = __riscv_vand_tu(vPb_i8, vPb_i8, 0, vl);
1406→            vPb2_i8 = __riscv_vand_tu(vPb2_i8, vPb2_i8, 0, vl);
1407→
1408→            vl = __riscv_vsetvl_e8m2(colCnt);
1409→            //load src1
1410→            vSrc1_i8 = __riscv_vle8_tu(vSrc1_i8, src1, vl);
1411→            vPa2_i8 = __riscv_vle8_tu(vPa2_i8, pA2, vl);
1412→            vPa3_i8 = __riscv_vle8_tu(vPa3_i8, pA3, vl);
1413→            vPa4_i8 = __riscv_vle8_tu(vPa4_i8, pA4, vl);
1414→            //load src2
1415→            vPb_i8 = __riscv_vle8_tu(vPb_i8, pB, vl);
1416→            vPb2_i8 = __riscv_vle8_tu(vPb2_i8, pB2, vl);
1417→
1418→            //bump pointers and update loop counter
