703→    if (pBuffer != (q7_t *)in_tmp_buf)
704→    {
705→        const q7_t *pA = ker_weight;
706→        int i;
707→
708→        for (i = 0; i < out_tensor_ch; i++)
709→        {
710→            long sum = 0;
711→            q7_t *pB = (q7_t*)in_tmp_buf;
712→
713→            /* basically each time it process 8 entries */
714→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 3;
715→
716→            while (colCnt)
717→            {
718→                long inA1, inB1;
719→                inA1 = *__SIMD64(pA)++;
720→                inB1 = *__SIMD64(pB)++;
721→                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
722→                colCnt--;
723→            }
724→            //sum up the high and low part results (SIMD results)
725→            sum = (q31_t)(sum >> 32) + (q31_t)sum;
726→
727→            colCnt = 3 * ker_dim * ker_dim & 0x7;
728→            while (colCnt)
729→            {
730→                q7_t inA1 = *pA++;
731→                q7_t inB1 = *pB++;
732→                sum += inA1 * inB1;
733→                colCnt--;
734→            }
735→
736→            //add bias back
737→            sum += *bias++;
738→
739→            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
740→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
741→        }
742→    }
743→#else
744→    if (pBuffer != (q7_t *)in_tmp_buf)
745→    {
746→        const q7_t *pA = ker_weight;
747→        int i;
748→
749→        for (i = 0; i < out_tensor_ch; i++)
750→        {
751→            long sum = *bias++;
752→            q7_t *pB = (q7_t*)in_tmp_buf;
753→
754→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
755→            while (colCnt)
756→            {
757→                long inA1, inB1;
758→                inA1 = *__SIMD32(pA)++;
759→                inB1 = *__SIMD32(pB)++;
760→                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
761→                colCnt--;
762→            }
763→
764→            colCnt = 3 * ker_dim * ker_dim & 0x3;
765→            while (colCnt)
766→            {
767→                q7_t inA1 = *pA++;
768→                q7_t inB1 = *pB++;
769→                sum += inA1 * inB1;
770→                colCnt--;
771→            }
772→
773→            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
774→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
775→        }
776→    }
777→#endif
778→#elif defined(ENA_DSP_ISA)
779→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
780→
781→    /*
782→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
783→     *  im2col are done to output in q15_t format from q7_t input
784→     */
785→    q7_t *wt_tmp = (q7_t*)ker_weight;
786→    q15_t *pBuffer = in_tmp_buf;
787→    q7_t *pOut = out_tensor;
788→
789→    uint32_t i;
790→    uint16_t size;
791→    uint16_t size2 = (3 * ker_dim * ker_dim) >> 2;
792→    q31_t tmp;
793→    q31_t *pwt2 = (q31_t *)wt_tmp_buf;
794→    for (i = 0; i < out_tensor_ch; i++)
795→    {
796→        size = size2;
797→        while (size != 0)
798→        {
799→            tmp = *__SIMD32(wt_tmp)++;;
800→            *pwt2++ = NDS_DSP_SUNPKD810(tmp);
801→            *pwt2++ = NDS_DSP_SUNPKD810(tmp >> 16);
802→            size--;
803→        }
804→        q7_t tmp1 = *wt_tmp++;
805→        q7_t tmp2 = *wt_tmp++;
806→        *pwt2++ = NDS_DSP_PKBB16(tmp2, tmp1);
807→        tmp1 = *wt_tmp++;
808→        *pwt2++ = (u16_t)tmp1;
809→    }
810→
811→    // This part implements the im2col function
812→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
813→    {
814→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
815→        {
816→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
817→            {
818→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
819→                {
820→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
821→                    {
822→                        *pBuffer++ = 0;
823→                        *pBuffer++ = 0;
824→                        *pBuffer++ = 0;
825→                    }
826→                    else
827→                    {
828→                        const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
829→                        *pBuffer++ = *pPixel++;
830→                        *pBuffer++ = *pPixel++;
831→                        *pBuffer++ = *pPixel++;
832→                    }
833→                }
834→            }
835→            *pBuffer++ = 0;
836→
837→            if (pBuffer == in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
838→            {
839→                pOut = nn_mat_mul_kernel_q15_q15_q7_bias_2sft(wt_tmp_buf, in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, pre_rshift, out_scale, post_rshift, bias, pOut);
840→                pBuffer = in_tmp_buf;
841→            }
842→        }
843→    }
844→
845→    if (pBuffer != in_tmp_buf)
846→    {
847→        const q7_t *pA = ker_weight;
848→        int i;
849→
850→        for (i = 0; i < out_tensor_ch; i++)
851→        {
852→            q31_t   sum = bias[i];
853→            q15_t   *pB = in_tmp_buf;
854→
855→            /* basically each time it process 4 entries */
856→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
857→
858→            while (colCnt)
859→            {
860→                q31_t     inA1, inA2;
861→                q31_t     inB1, inB2;
862→
863→                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
864→                inB1 = *__SIMD32(pB)++;
865→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
866→                inB2 = *__SIMD32(pB)++;
867→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
868→
869→                colCnt--;
870→            }
871→            colCnt = 3 * ker_dim * ker_dim & 0x3;
872→            while (colCnt)
873→            {
874→                q7_t      inA1 = *pA++;
875→                q15_t     inB1 = *pB++;
876→                sum += inA1 * inB1;
877→                colCnt--;
878→            }
879→
880→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
881→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
882→        }
883→    }
884→#else
885→    uint16_t  i, j, k, l, m, n;
886→    int       conv_out;
887→    long in_row, in_col;
888→
889→    for (i = 0; i < out_tensor_ch; i++)
890→    {
891→        for (j = 0; j < out_tensor_dim; j++)
892→        {
893→            for (k = 0; k < out_tensor_dim; k++)
894→            {
895→                conv_out = bias[i];
896→                for (m = 0; m < ker_dim; m++)
897→                {
898→                    for (n = 0; n < ker_dim; n++)
899→                    {
900→                        /* if-for implementation */
901→                        in_row = stride * j + m - pad;
902→                        in_col = stride * k + n - pad;
903→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
904→                        {
905→                            for (l = 0; l < 3; l++)
906→                            {
907→                                conv_out +=
908→                                    in_tensor[(in_row * in_tensor_dim + in_col) * 3 + l]
909→                                    * ker_weight[i * 3 * ker_dim * ker_dim + (m * ker_dim + n) * 3 + l];
910→                            }
911→                        }
912→                    }
913→                }
914→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
915→                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
916→            }
917→        }
918→    }
919→#endif
920→
921→    return 0;
922→}
