    /* Transpose weights once: from [out_ch x K] to [K x out_ch] */
    const long row = out_tensor_ch;
    const long col = ker_dim * ker_dim * in_tensor_ch;
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);

    /* Total output pixels */
    long total_pixels = (long)out_tensor_dim * out_tensor_dim;
    long pixel_idx = 0;

    /* Process 2 output pixels at a time */
    for (; pixel_idx + 1 < total_pixels; pixel_idx += 2)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;
        long out_y2 = (pixel_idx + 1) / out_tensor_dim;
        long out_x2 = (pixel_idx + 1) % out_tensor_dim;

        /* Load bias into accumulators: v0 (pixel1), v8 (pixel2) at e32/M8 */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V0, bias);
        NDS_VEC_VLE32_V(NDS_VEC_V8, bias);

        /* Accumulate over all K positions */
        for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
        {
            long in_row1 = out_y1 * stride - pad + i_ker_y;
            long in_row2 = out_y2 * stride - pad + i_ker_y;

            for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
            {
                long in_col1 = out_x1 * stride - pad + i_ker_x;
                long in_col2 = out_x2 * stride - pad + i_ker_x;
                long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;

                for (ch = 0; ch < in_tensor_ch; ch++)
                {
                    long k_pos = k_base + ch;

                    /* Load transposed weight row into v16 at e8/M2 */
                    NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);

                    /* Get input scalars */
                    q7_t a1 = 0, a2 = 0;
                    if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                        in_col1 >= 0 && in_col1 < in_tensor_dim)
                        a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                    if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
                        in_col2 >= 0 && in_col2 < in_tensor_dim)
                        a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];

                    /* vqmacc.vx: acc[e32/M8] += scalar * wt[e8/M2] */
                    NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                    NDS_VEC_VQMACC_VX(NDS_VEC_V8, a2, NDS_VEC_V16);
                }
            }
        }

        /* Requantize pixel 1: shift, scale, narrow, clip, store */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
        pOut += out_tensor_ch;

        /* Requantize pixel 2 */
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VSRA_VX(NDS_VEC_V8, NDS_VEC_V8, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V8, NDS_VEC_V8, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V8, NDS_VEC_V8, 0);
        NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
        pOut += out_tensor_ch;
    }

    /* Handle the last pixel if total_pixels is odd */
    if (pixel_idx < total_pixels)
    {
        long out_y1 = pixel_idx / out_tensor_dim;
        long out_x1 = pixel_idx % out_tensor_dim;

        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VLE32_V(NDS_VEC_V0, bias);

        for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
        {
            long in_row1 = out_y1 * stride - pad + i_ker_y;
            for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
            {
                long in_col1 = out_x1 * stride - pad + i_ker_x;
                long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
                for (ch = 0; ch < in_tensor_ch; ch++)
                {
                    long k_pos = k_base + ch;
                    NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
                    NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch);
                    q7_t a1 = 0;
                    if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
                        in_col1 >= 0 && in_col1 < in_tensor_dim)
                        a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
                    NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
                }
            }
        }

        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
        NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
        NDS_VEC_VSETVLI(vl, out_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
        NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, 0);
        NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
        pOut += out_tensor_ch;
    }
#else /* NDS_VEC_RVV_VERSION < 1000: fallback to tiling GEMM */

