 863→            while (colCnt)
 864→            {
 865→                long inA1, inB1;
 866→                inA1 = *__SIMD64(pA)++;
 867→                inB1 = *__SIMD64(pB)++;
 868→                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
 869→                colCnt--;
 870→            }
 871→            //sum up the high and low part results (SIMD results)
 872→            sum = (q31_t)(sum >> 32) + (q31_t)sum;
 873→
 874→            colCnt = 3 * ker_dim * ker_dim & 0x7;
 875→            while (colCnt)
 876→            {
 877→                q7_t inA1 = *pA++;
 878→                q7_t inB1 = *pB++;
 879→                sum += inA1 * inB1;
 880→                colCnt--;
 881→            }
 882→
 883→            //add bias back
 884→            sum += *bias++;
 885→
 886→            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
 887→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
 888→        }
 889→    }
 890→#else
 891→    if (pBuffer != (q7_t *)in_tmp_buf)
 892→    {
 893→        const q7_t *pA = ker_weight;
 894→        int i;
 895→
 896→        for (i = 0; i < out_tensor_ch; i++)
 897→        {
 898→            long sum = *bias++;
 899→            q7_t *pB = (q7_t*)in_tmp_buf;
 900→
 901→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
 902→            while (colCnt)
 903→            {
 904→                long inA1, inB1;
 905→                inA1 = *__SIMD32(pA)++;
 906→                inB1 = *__SIMD32(pB)++;
 907→                sum = NDS_DSP_SMAQA(sum, inA1, inB1);
 908→                colCnt--;
 909→            }
 910→
 911→            colCnt = 3 * ker_dim * ker_dim & 0x3;
 912→            while (colCnt)
 913→            {
 914→                q7_t inA1 = *pA++;
 915→                q7_t inB1 = *pB++;
