 945→        {
 946→            tmp = *__SIMD32(wt_tmp)++;;
 947→            *pwt2++ = NDS_DSP_SUNPKD810(tmp);
 948→            *pwt2++ = NDS_DSP_SUNPKD810(tmp >> 16);
 949→            size--;
 950→        }
