 952→        q7_t tmp2 = *wt_tmp++;
 953→        *pwt2++ = NDS_DSP_PKBB16(tmp2, tmp1);
 954→        tmp1 = *wt_tmp++;
 955→        *pwt2++ = (u16_t)tmp1;
 956→    }
 957→
 958→    // This part implements the im2col function
 959→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
 960→    {
 961→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
 962→        {
 963→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
