 987→                pBuffer = in_tmp_buf;
 988→            }
 989→        }
 990→    }
 991→
 992→    if (pBuffer != in_tmp_buf)
 993→    {
 994→        const q7_t *pA = ker_weight;
 995→        int i;
 996→
 997→        for (i = 0; i < out_tensor_ch; i++)
 998→        {
 999→            q31_t   sum = bias[i];
1000→            q15_t   *pB = in_tmp_buf;
1001→
1002→            /* basically each time it process 4 entries */
1003→            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
1004→
1005→            while (colCnt)
1006→            {
1007→                q31_t     inA1, inA2;
1008→                q31_t     inB1, inB2;
1009→
1010→                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
1011→                inB1 = *__SIMD32(pB)++;
1012→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
1013→                inB2 = *__SIMD32(pB)++;
1014→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
1015→
1016→                colCnt--;
1017→            }
1018→            colCnt = 3 * ker_dim * ker_dim & 0x3;
1019→            while (colCnt)
1020→            {
1021→                q7_t      inA1 = *pA++;
1022→                q15_t     inB1 = *pB++;
1023→                sum += inA1 * inB1;
1024→                colCnt--;
1025→            }
1026→
1027→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1028→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
1029→        }
1030→    }
1031→#else
1032→    uint16_t  i, j, k, l, m, n;
1033→    int       conv_out;
1034→    long in_row, in_col;
1035→
1036→    for (i = 0; i < out_tensor_ch; i++)
1037→    {
1038→        for (j = 0; j < out_tensor_dim; j++)
1039→        {
1040→            for (k = 0; k < out_tensor_dim; k++)
1041→            {
1042→                conv_out = bias[i];
1043→                for (m = 0; m < ker_dim; m++)
1044→                {
1045→                    for (n = 0; n < ker_dim; n++)
1046→                    {
1047→                        /* if-for implementation */
1048→                        in_row = stride * j + m - pad;
1049→                        in_col = stride * k + n - pad;
1050→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
1051→                        {
